const niche = $.input.niche;
const count = $.input.videoCount || 5;
const prompt = `You are an expert social media video content strategist. Generate ${count} unique short-form video concepts for the niche: "${niche}".

Each video concept should be optimized for TikTok, Instagram Reels, and YouTube Shorts (15-60 seconds).

Return ONLY valid JSON with this exact structure:
{
  "niche": "${niche}",
  "concepts": [
    {
      "number": 1,
      "title": "<catchy video title>",
      "hook": "<attention-grabbing first 3 seconds script>",
      "script": "<full 30-45 second video script with scene directions in brackets>",
      "hashtags": "<5-8 relevant hashtags as a single string>",
      "targetPlatform": "<tiktok|reels|shorts|all>",
      "estimatedDuration": "<duration in seconds>",
      "viralPotential": "<high|medium|low>"
    }
  ],
  "contentStrategy": "<brief 2-sentence strategy note for this content batch>"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { niche: $.input.niche, concepts: [], contentStrategy: raw.slice(0, 500) }; }

const ai = $.steps.parseAI.output;
const concepts = ai.concepts || [];
const now = new Date().toISOString().split('T')[0];

const sheetData = concepts.map(c => ({
  'Date': now,
  'Number': c.number || '',
  'Title': c.title || '',
  'Hook': c.hook || '',
  'Script': (c.script || '').slice(0, 500),
  'Hashtags': c.hashtags || '',
  'Platform': c.targetPlatform || 'all',
  'Duration': c.estimatedDuration || '',
  'Viral Potential': c.viralPotential || '',
  'Status': 'Draft',
  'Niche': ai.niche || $.input.niche
}));

return { sheetData, conceptCount: concepts.length, strategy: ai.contentStrategy || '' };

const ai = $.steps.parseAI.output;
const concepts = ai.concepts || [];
const niche = ai.niche || $.input.niche;
const strategy = $.steps.prepareSheetData.output.strategy;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':movie_camera: Video Content Plan: ' + niche, emoji: true } });

if (strategy) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + strategy } });
}
blocks.push({ type: 'divider' });

concepts.slice(0, 5).forEach((c, i) => {
  let text = '*' + (c.number || i + 1) + '. ' + (c.title || 'Untitled') + '*\n';
  text += ':zap: *Hook:* ' + (c.hook || '') + '\n';
  text += ':dart: *Platform:* ' + (c.targetPlatform || 'all') + ' | :clock1: ' + (c.estimatedDuration || '30s') + ' | :fire: ' + (c.viralPotential || 'medium') + '\n';
  text += (c.hashtags || '');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
  if (i < concepts.length - 1) blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: concepts.length + ' concepts generated | Saved to Google Sheets | One CLI + Claude AI' }] });

const fallback = 'Video Content Plan: ' + concepts.length + ' concepts for ' + niche;
return { blocks, fallback };
